import{_ as t,c as d,ag as a,o as i}from"./chunks/framework.BcsBtVhd.js";const u=JSON.parse('{"title":"命令使用说明（Scripts Usage）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scripts-usage.md","filePath":"guide/scripts-usage.md"}'),c={name:"guide/scripts-usage.md"};function o(l,e,s,r,p,n){return i(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="命令使用说明-scripts-usage" tabindex="-1">命令使用说明（Scripts Usage） <a class="header-anchor" href="#命令使用说明-scripts-usage" aria-label="Permalink to &quot;命令使用说明（Scripts Usage）&quot;">​</a></h1><blockquote><p>本文用于统一团队对 <code>package.json scripts</code> 的理解，避免误用。</p></blockquote><h2 id="一、日常开发" tabindex="-1">一、日常开发 <a class="header-anchor" href="#一、日常开发" aria-label="Permalink to &quot;一、日常开发&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>作用</th><th>何时使用</th></tr></thead><tbody><tr><td><code>pnpm start</code></td><td>同时启动 React + Vue 文档开发服务</td><td>日常联调、对比两端展示</td></tr><tr><td><code>pnpm start:react</code></td><td>仅启动 React 文档（dumi）</td><td>只改 React 文档/组件展示</td></tr><tr><td><code>pnpm start:vue</code></td><td>仅启动 Vue 文档（VitePress）</td><td>只改 Vue 文档/交互</td></tr><tr><td><code>pnpm preview</code></td><td>同时预览 React + Vue 构建产物</td><td>本地验收发布前静态产物</td></tr><tr><td><code>pnpm preview:react</code></td><td>预览 React 构建产物</td><td>检查 dumi build 输出</td></tr><tr><td><code>pnpm preview:vue</code></td><td>预览 Vue 构建产物</td><td>检查 vitepress build 输出</td></tr></tbody></table><hr><h2 id="二、生成与构建" tabindex="-1">二、生成与构建 <a class="header-anchor" href="#二、生成与构建" aria-label="Permalink to &quot;二、生成与构建&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>作用</th><th>何时使用</th></tr></thead><tbody><tr><td><code>pnpm generate</code></td><td>全量生成（core/react/vue）</td><td>推荐默认，保证三端产物同步</td></tr><tr><td><code>pnpm generate:core</code></td><td>仅生成 icons-svg</td><td>改了 <code>packages/core/svg</code> 时先跑</td></tr><tr><td><code>pnpm generate:react</code></td><td>仅生成 React 图标层</td><td>只改 React 模板或 React 适配层</td></tr><tr><td><code>pnpm generate:vue</code></td><td>仅生成 Vue 图标层</td><td>只改 Vue 模板或 Vue 适配层</td></tr><tr><td><code>pnpm build</code></td><td>先 <code>build:core</code>，再并行 <code>build:react + build:vue</code></td><td>推荐默认构建命令</td></tr><tr><td><code>pnpm build:core</code></td><td>仅构建 icons-svg</td><td>只验证 core 包</td></tr><tr><td><code>pnpm build:react</code></td><td>仅构建 React 包</td><td>只验证 React 包</td></tr><tr><td><code>pnpm build:vue</code></td><td>仅构建 Vue 包</td><td>只验证 Vue 包</td></tr><tr><td><code>pnpm site</code></td><td>构建 React + Vue 文档站</td><td>发布前统一构建文档</td></tr><tr><td><code>pnpm site:react</code></td><td>构建 React 文档站</td><td>只发布/检查 React 文档</td></tr><tr><td><code>pnpm site:vue</code></td><td>构建 Vue 文档站</td><td>只发布/检查 Vue 文档</td></tr></tbody></table><hr><h2 id="三、测试与-ci" tabindex="-1">三、测试与 CI <a class="header-anchor" href="#三、测试与-ci" aria-label="Permalink to &quot;三、测试与 CI&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>作用</th><th>何时使用</th></tr></thead><tbody><tr><td><code>pnpm test</code></td><td>执行 smoke test</td><td>每次提交前建议执行</td></tr><tr><td><code>pnpm test:smoke</code></td><td>校验关键产物/关键文件是否存在</td><td>快速冒烟检查</td></tr><tr><td><code>pnpm ci:check</code></td><td>CI 检查入口（等价 <code>release:check</code>）</td><td>本地模拟 CI</td></tr></tbody></table><hr><h2 id="四、发布流程" tabindex="-1">四、发布流程 <a class="header-anchor" href="#四、发布流程" aria-label="Permalink to &quot;四、发布流程&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>作用</th><th>何时使用</th></tr></thead><tbody><tr><td><code>pnpm release:check</code></td><td><code>generate + build + test</code></td><td>发版前全量校验</td></tr><tr><td><code>pnpm release:version</code></td><td>用 lerna 递增版本号</td><td>确认发版后执行</td></tr><tr><td><code>pnpm release:prepare</code></td><td><code>release:version + build + test</code></td><td>版本变更后二次确认</td></tr><tr><td><code>pnpm release:publish</code></td><td>递归发布 npm 包</td><td>最终发包</td></tr><tr><td><code>pnpm release:ship</code></td><td><code>check -&gt; prepare -&gt; publish</code> 一键发版</td><td>推荐发版入口</td></tr></tbody></table><hr><h2 id="五、推荐工作流" tabindex="-1">五、推荐工作流 <a class="header-anchor" href="#五、推荐工作流" aria-label="Permalink to &quot;五、推荐工作流&quot;">​</a></h2><h3 id="日常改动-默认" tabindex="-1">日常改动（默认） <a class="header-anchor" href="#日常改动-默认" aria-label="Permalink to &quot;日常改动（默认）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generate</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><h3 id="仅-vue-改动-提速" tabindex="-1">仅 Vue 改动（提速） <a class="header-anchor" href="#仅-vue-改动-提速" aria-label="Permalink to &quot;仅 Vue 改动（提速）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generate:vue</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:vue</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><h3 id="正式发版" tabindex="-1">正式发版 <a class="header-anchor" href="#正式发版" aria-label="Permalink to &quot;正式发版&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> release:ship</span></span></code></pre></div><hr><h2 id="六、注意事项" tabindex="-1">六、注意事项 <a class="header-anchor" href="#六、注意事项" aria-label="Permalink to &quot;六、注意事项&quot;">​</a></h2><ol><li>改了 <code>packages/core/svg</code> 后，建议使用全量 <code>generate/build</code>，确保 React/Vue 同步。</li><li><code>pnpm publish --recursive --tag latest</code> 会发布所有可发布子包，请在 <code>release:check</code> 通过后再执行。</li><li>若需清理依赖可使用 <code>pnpm clean</code>，但这是重操作（会删除所有子包 <code>node_modules</code>）。</li></ol><hr><h2 id="七、github-工作流说明-重点" tabindex="-1">七、GitHub 工作流说明（重点） <a class="header-anchor" href="#七、github-工作流说明-重点" aria-label="Permalink to &quot;七、GitHub 工作流说明（重点）&quot;">​</a></h2><h3 id="deploy-yml-文档部署" tabindex="-1"><code>deploy.yml</code>（文档部署） <a class="header-anchor" href="#deploy-yml-文档部署" aria-label="Permalink to &quot;`deploy.yml`（文档部署）&quot;">​</a></h3><p>用途：发布文档站到 GitHub Pages。</p><ul><li>触发：<code>master/main</code> push</li><li>主要命令：<code>pnpm generate &amp;&amp; pnpm build &amp;&amp; pnpm site</code></li><li>产物： <ul><li><code>/react</code>（dumi 文档）</li><li><code>/vue</code>（vitepress 文档）</li></ul></li></ul><h3 id="release-yml-npm-发包" tabindex="-1"><code>release.yml</code>（npm 发包） <a class="header-anchor" href="#release-yml-npm-发包" aria-label="Permalink to &quot;`release.yml`（npm 发包）&quot;">​</a></h3><p>用途：发布 npm 包（<code>@colelab/icons-*</code>）。</p><ul><li>触发：手动触发（workflow_dispatch）</li><li>认证：OIDC Trusted Publishing（不使用长期 <code>NPM_TOKEN</code>）</li><li>主要命令：<code>release:check</code> -&gt;（可选 <code>release:version</code>）-&gt; <code>release:publish</code></li></ul><h3 id="一句话区分" tabindex="-1">一句话区分 <a class="header-anchor" href="#一句话区分" aria-label="Permalink to &quot;一句话区分&quot;">​</a></h3><ul><li><code>deploy.yml</code> = <strong>发文档</strong></li><li><code>release.yml</code> = <strong>发包</strong></li></ul><hr><h2 id="八、命令产物目录说明-generate-build" tabindex="-1">八、命令产物目录说明（Generate / Build） <a class="header-anchor" href="#八、命令产物目录说明-generate-build" aria-label="Permalink to &quot;八、命令产物目录说明（Generate / Build）&quot;">​</a></h2><h3 id="pnpm-generate-会生成的目录" tabindex="-1"><code>pnpm generate</code> 会生成的目录 <a class="header-anchor" href="#pnpm-generate-会生成的目录" aria-label="Permalink to &quot;`pnpm generate` 会生成的目录&quot;">​</a></h3><ol><li><p><code>generate:core</code>（<code>@colelab/icons-svg</code>）</p><ul><li><code>packages/core/src</code></li><li><code>packages/core/inline-svg</code></li><li><code>packages/core/inline-namespaced-svg</code></li></ul></li><li><p><code>generate:react</code>（<code>@colelab/icons-react</code>）</p><ul><li><code>packages/react/src/icons</code></li></ul></li><li><p><code>generate:vue</code>（<code>@colelab/icons-vue</code>）</p><ul><li><code>packages/vue/src/icons</code></li></ul></li></ol><h3 id="pnpm-build-会生成的目录" tabindex="-1"><code>pnpm build</code> 会生成的目录 <a class="header-anchor" href="#pnpm-build-会生成的目录" aria-label="Permalink to &quot;`pnpm build` 会生成的目录&quot;">​</a></h3><ol><li><p><code>build:core</code></p><ul><li><code>packages/core/es</code></li><li><code>packages/core/lib</code></li></ul></li><li><p><code>build:react</code></p><ul><li><code>packages/react/es</code></li><li><code>packages/react/lib</code></li></ul></li><li><p><code>build:vue</code></p><ul><li><code>packages/vue/es</code></li><li><code>packages/vue/lib</code></li></ul></li></ol><h3 id="文档构建相关目录-补充" tabindex="-1">文档构建相关目录（补充） <a class="header-anchor" href="#文档构建相关目录-补充" aria-label="Permalink to &quot;文档构建相关目录（补充）&quot;">​</a></h3><ul><li><code>pnpm site:react</code> 产物：<code>dist</code></li><li><code>pnpm site:vue</code> 产物：<code>docs-vue/.vitepress/dist</code></li><li>部署聚合目录：<code>deploy-dist</code></li></ul><blockquote><p>说明：<code>cache/dist/es/lib</code> 等构建产物目录不建议提交到 Git 仓库。</p></blockquote>',43)])])}const b=t(c,[["render",o]]);export{u as __pageData,b as default};
